package com.google.gson.examples.android.model;

import static org.junit.jupiter.api.Assertions.*;
import org.junit.jupiter.api.Test;

class LineItemTest {

  @Test
  void testLineItemConstructorAndGetters() throws Exception {
    String name = "TestItem";
    int quantity = 5;
    long priceInMicros = 123456789L;
    String currencyCode = "USD";

    // Directly instantiate LineItem instead of reflection
    LineItem item = new LineItem(name, quantity, priceInMicros, currencyCode);

    assertEquals(name, item.getName());
    assertEquals(quantity, item.getQuantity());
    assertEquals(priceInMicros, item.getPriceInMicros());
    assertEquals(currencyCode, item.getCurrencyCode());
  }

  @Test
  void testToStringNotNullAndContainsFields() throws Exception {
    LineItem item = new LineItem("Name", 1, 1000L, "EUR");
    String toString = item.toString();
    assertNotNull(toString);
    assertTrue(toString.contains("Name"));
    assertTrue(toString.contains("1"));
    assertTrue(toString.contains("1000"));
    assertTrue(toString.contains("EUR"));
  }
}
